const glossary = {
  en: [
    { term: 'Carrier', def: 'A transportation provider responsible for moving goods from one location to another. In OTM, carriers interact with shippers to receive and execute shipment tenders.' },
    { term: 'Shipment Tender', def: 'A formal request sent by the shipper (or OTM system) to a carrier, offering them the opportunity to transport goods. The carrier can accept or reject the tender based on availability and pricing.' },
    { term: 'Tender Acceptance/Rejection', def: 'The process by which a carrier accepts or rejects a shipment offer within OTM. Carriers are expected to respond promptly to ensure timely planning and execution.' },
    { term: 'Transportation Mode', def: 'The type of transportation used to move goods (e.g., road, rail, air, or sea). Carriers define the modes they support within OTM for specific routes or regions.' },
    { term: 'Accessorial Charges', def: 'Additional fees carriers charge for services beyond standard transportation, such as fuel surcharges, loading/unloading fees, or storage costs.' },
    { term: 'Service Level Agreement (SLA)', def: 'A contractual commitment between the shipper and carrier that defines expected performance standards, such as on-time delivery, transit times, and service quality.' },
    { term: 'Shipment Execution', def: 'The process where a carrier performs the transportation of goods as per the shipment tender. Includes pick-up, in-transit management, and delivery.' },
    { term: 'Status Update', def: 'Real-time updates provided by the carrier in OTM to inform the shipper about the current location or condition of the shipment (e.g., "Picked up," "In transit," "Delivered").' },
    { term: 'Track and Trace', def: 'The process of monitoring the shipment\'s movement from origin to destination.' },
    { term: 'Compliance Management', def: 'Ensuring that the carrier meets all regulatory requirements, including safety certifications, insurance coverage, and driver qualifications.' },
    { term: 'Transport Document', def: 'A legal document provided by the carrier to the shipper, detailing the type, quantity, and destination of the goods being shipped. OTM integrates transport document data to manage and track shipments.' },
    { term: 'Proof of Delivery (POD)', def: 'A document or electronic confirmation provided by the carrier once goods are delivered to the consignee. Used to confirm successful delivery, often required for payment and closing out the shipment in OTM.' },
    { term: 'Transportation Planning', def: 'The process within OTM that optimizes the selection of carriers, routes, and shipment schedules based on costs, service levels, and other factors.' },
    { term: 'Shipment ID', def: 'A unique identifier assigned to each shipment within OTM, used to track and manage all aspects of the shipment from tendering to final delivery.' },
    { term: 'Dock Scheduling', def: 'The process of scheduling and managing the arrival and departure of carriers at loading docks. OTM provides carriers with dock appointment schedules to minimize waiting times.' },
    { term: 'Transport Capacity', def: 'The total available space or resources (e.g., vehicles, containers) a carrier has for shipping goods.' },
    { term: 'Carrier Portal', def: 'An online platform in OTM where carriers can view and manage shipment tenders, update statuses, submit invoices, and communicate with shippers.' },
  ],
  es: [
    { term: 'Transportista', def: 'Proveedor de transporte responsable de mover mercancías de un lugar a otro. En OTM, los transportistas interactúan con los cargadores para recibir y ejecutar licitaciones de envío.' },
    { term: 'Licitación de Envío', def: 'Solicitud formal enviada por el cargador (o el sistema OTM) a un transportista, ofreciéndole la oportunidad de transportar mercancías. El transportista puede aceptar o rechazar según disponibilidad y precio.' },
    { term: 'Aceptación/Rechazo de Licitación', def: 'Proceso por el cual un transportista acepta o rechaza una oferta de envío en OTM. Se espera que los transportistas respondan con prontitud para garantizar una planificación y ejecución oportunas.' },
    { term: 'Modal de Transporte', def: 'Tipo de transporte utilizado para mover mercancías (ej. carretera, ferrocarril, aéreo o marítimo). Los transportistas definen los modos que soportan en OTM para rutas o regiones específicas.' },
    { term: 'Cargos Adicionales', def: 'Tarifas adicionales que los transportistas cobran por servicios más allá del transporte estándar, como recargos de combustible, tarifas de carga/descarga o costos de almacenamiento.' },
    { term: 'Acuerdo de Nivel de Servicio (SLA)', def: 'Compromiso contractual entre el cargador y el transportista que define los estándares de desempeño esperados, como entrega a tiempo, tiempos de tránsito y calidad del servicio.' },
    { term: 'Ejecución de Envío', def: 'Proceso donde el transportista realiza el transporte de mercancías según la licitación. Incluye la recogida, gestión en tránsito y entrega.' },
    { term: 'Actualización de Estado', def: 'Actualizaciones en tiempo real proporcionadas por el transportista en OTM para informar al cargador sobre la ubicación o condición actual del envío.' },
    { term: 'Rastreo y Seguimiento', def: 'Proceso de monitoreo del movimiento del envío desde el origen hasta el destino.' },
    { term: 'Gestión de Cumplimiento', def: 'Garantizar que el transportista cumpla con todos los requisitos regulatorios, incluidas las certificaciones de seguridad, cobertura de seguro y calificaciones del conductor.' },
    { term: 'Documento de Transporte', def: 'Documento legal proporcionado por el transportista al cargador, detallando el tipo, cantidad y destino de las mercancías. OTM integra los datos del documento de transporte para gestionar y rastrear los envíos.' },
    { term: 'Prueba de Entrega (POD)', def: 'Documento o confirmación electrónica proporcionada por el transportista una vez que las mercancías son entregadas al consignatario. Se usa para confirmar la entrega exitosa, a menudo requerida para el pago.' },
    { term: 'Planificación de Transporte', def: 'Proceso dentro de OTM que optimiza la selección de transportistas, rutas y horarios de envío basándose en costos, niveles de servicio y otros factores.' },
    { term: 'ID de Envío', def: 'Identificador único asignado a cada envío en OTM, utilizado para rastrear y gestionar todos los aspectos del envío desde la licitación hasta la entrega final.' },
    { term: 'Programación de Muelles', def: 'Proceso de programación y gestión de la llegada y salida de transportistas en los muelles de carga. OTM proporciona horarios de citas para minimizar tiempos de espera.' },
    { term: 'Capacidad de Transporte', def: 'Espacio total disponible o recursos (ej. vehículos, contenedores) que un transportista tiene para enviar mercancías.' },
    { term: 'Portal del Transportista', def: 'Plataforma en línea en OTM donde los transportistas pueden ver y gestionar licitaciones, actualizar estados, enviar facturas y comunicarse con los cargadores.' },
  ],
  pt: [
    { term: 'Transportadora', def: 'Prestador de serviço de transporte responsável por mover mercadorias de um local para outro. No OTM, as transportadoras interagem com os embarcadores para receber e executar ofertas de frete.' },
    { term: 'Oferta de Frete', def: 'Solicitação formal enviada pelo embarcador (ou pelo sistema OTM) a uma transportadora, oferecendo a oportunidade de transportar mercadorias. A transportadora pode aceitar ou rejeitar conforme disponibilidade e preço.' },
    { term: 'Aceitação/Rejeição de Oferta', def: 'Processo pelo qual uma transportadora aceita ou rejeita uma oferta de remessa no OTM. As transportadoras devem responder prontamente para garantir planejamento e execução oportunos.' },
    { term: 'Modal de Transporte', def: 'Tipo de transporte usado para mover mercadorias (ex: rodoviário, ferroviário, aéreo ou marítimo). As transportadoras definem os modais que suportam no OTM para rotas ou regiões específicas.' },
    { term: 'Cobranças Adicionais', def: 'Taxas extras cobradas pelas transportadoras por serviços além do transporte padrão, como sobretaxas de combustível, taxas de carga/descarga ou custos de armazenagem.' },
    { term: 'Acordo de Nível de Serviço (SLA)', def: 'Compromisso contratual entre o embarcador e a transportadora que define os padrões de desempenho esperados, como entrega no prazo, tempos de trânsito e qualidade do serviço.' },
    { term: 'Execução de Remessa', def: 'Processo em que a transportadora realiza o transporte das mercadorias conforme a oferta de frete. Inclui coleta, gestão em trânsito e entrega.' },
    { term: 'Atualização de Status', def: 'Atualizações em tempo real fornecidas pela transportadora no OTM para informar o embarcador sobre a localização ou condição atual da remessa.' },
    { term: 'Rastreamento', def: 'Processo de monitoramento do movimento da remessa desde a origem até o destino.' },
    { term: 'Gestão de Conformidade', def: 'Garantir que a transportadora atenda a todos os requisitos regulatórios, incluindo certificações de segurança, cobertura de seguro e qualificações dos motoristas.' },
    { term: 'Documento de Transporte', def: 'Documento legal fornecido pela transportadora ao embarcador, detalhando o tipo, quantidade e destino das mercadorias. O OTM integra os dados do documento de transporte para gerenciar e rastrear as remessas.' },
    { term: 'Comprovante de Entrega (POD)', def: 'Documento ou confirmação eletrônica fornecida pela transportadora após a entrega das mercadorias ao destinatário. Usado para confirmar a entrega bem-sucedida, geralmente necessário para pagamento.' },
    { term: 'Planejamento de Transporte', def: 'Processo no OTM que otimiza a seleção de transportadoras, rotas e programações de remessa com base em custos, níveis de serviço e outros fatores.' },
    { term: 'ID de Remessa', def: 'Identificador único atribuído a cada remessa no OTM, usado para rastrear e gerenciar todos os aspectos da remessa desde a oferta até a entrega final.' },
    { term: 'Agendamento de Docas', def: 'Processo de agendamento e gerenciamento da chegada e saída de transportadoras nas docas de carregamento. O OTM fornece agendamentos de horários para minimizar os tempos de espera.' },
    { term: 'Capacidade de Transporte', def: 'Espaço total disponível ou recursos (ex: veículos, contêineres) que uma transportadora tem para enviar mercadorias.' },
    { term: 'Portal da Transportadora', def: 'Plataforma online no OTM onde as transportadoras podem visualizar e gerenciar ofertas de frete, atualizar status, enviar faturas e se comunicar com os embarcadores.' },
  ]
}

const modules = {
  basic: [
    {
      id:1, video:null,
      en:{title:"Introduction",tag:"Module 1",desc:"Overview of the OTM training objectives, scope, and glossary.",
        content:`<h3>Objective</h3><p>The objective of this training is to efficiently manage relationships, performance, and interactions with carriers to ensure reliable, cost-effective, and timely transportation services across the supply chain.</p><h3>Scope</h3><ul><li>Overview of OTM and its role in logistics and transportation</li><li>Understanding key functionalities that transportation providers use in OTM</li><li>Receiving and managing shipment tenders</li><li>Shipment execution and status updates</li><li>Carrier collaboration with shippers</li><li>Compliance and risk management</li></ul><h3>Training Tips</h3><ul><li>Focus on details: review each section thoroughly before moving on</li><li>Take notes: jot down key points or questions during the training</li><li>Revisit sections: go back to any part if something is not clear</li></ul>`,
        quiz:[{q:"What is the primary objective of this OTM training?",options:["To learn how to code logistics software","To efficiently manage relationships, performance, and interactions with carriers","To replace the need for a transportation coordinator","To reduce the number of shipments processed"],correct:1},{q:"Which of the following is covered in the training scope?",options:["Financial auditing of carriers","Compliance and risk management","Warehouse construction","HR management for drivers"],correct:1}]},
      es:{title:"Introducción",tag:"Módulo 1",desc:"Descripción general de los objetivos, alcance y glosario de la capacitación OTM.",
        content:`<h3>Objetivo</h3><p>El objetivo de esta capacitación es gestionar de manera eficiente las relaciones, el rendimiento y las interacciones con los transportistas para garantizar servicios de transporte confiables, rentables y oportunos.</p><h3>Alcance</h3><ul><li>Descripción general de OTM y su rol en logística y transporte</li><li>Comprensión de las funcionalidades clave</li><li>Recepción y gestión de licitaciones de envío</li><li>Ejecución de envíos y actualizaciones de estado</li><li>Colaboración del transportista con los cargadores</li><li>Cumplimiento y gestión de riesgos</li></ul><h3>Consejos de capacitación</h3><ul><li>Enfócate en los detalles: revisa cada sección antes de continuar</li><li>Toma notas: anota puntos clave o preguntas durante la capacitación</li><li>Revisita secciones: vuelve a cualquier parte si algo no está claro</li></ul>`,
        quiz:[{q:"¿Cuál es el objetivo principal de esta capacitación OTM?",options:["Aprender a programar software logístico","Gestionar eficientemente las relaciones, el rendimiento y las interacciones con los transportistas","Reemplazar la necesidad de un coordinador de transporte","Reducir el número de envíos procesados"],correct:1},{q:"¿Cuál de los siguientes temas está incluido en el alcance?",options:["Auditoría financiera de transportistas","Cumplimiento y gestión de riesgos","Construcción de almacenes","Gestión de recursos humanos"],correct:1}]},
      pt:{title:"Introdução",tag:"Módulo 1",desc:"Visão geral dos objetivos, escopo e glossário do treinamento OTM.",
        content:`<h3>Objetivo</h3><p>O objetivo deste treinamento é gerenciar com eficiência os relacionamentos, o desempenho e as interações com transportadoras para garantir serviços de transporte confiáveis, econômicos e pontuais.</p><h3>Escopo</h3><ul><li>Visão geral do OTM e seu papel na logística</li><li>Funcionalidades principais usadas pelos prestadores de serviço</li><li>Recebimento e gestão de ofertas de frete</li><li>Execução de remessas e atualizações de status</li><li>Colaboração com embarcadores</li><li>Conformidade e gestão de riscos</li></ul><h3>Dicas de treinamento</h3><ul><li>Foque nos detalhes: revise cada seção antes de avançar</li><li>Faça anotações: registre pontos-chave ou dúvidas durante o treinamento</li><li>Revisite seções: volte a qualquer parte se algo não estiver claro</li></ul>`,
        quiz:[{q:"Qual é o principal objetivo deste treinamento OTM?",options:["Aprender a programar software de logística","Gerenciar com eficiência os relacionamentos, desempenho e interações com transportadoras","Substituir a necessidade de um coordenador de transporte","Reduzir o número de remessas processadas"],correct:1},{q:"Qual dos seguintes tópicos está incluído no escopo?",options:["Auditoria financeira de transportadoras","Conformidade e gestão de riscos","Construção de armazéns","Gestão de RH para motoristas"],correct:1}]}
    },
    { id:2, video:"https://wnypubltm64soaxh.public.blob.vercel-storage.com/module2.mp4", en:{title:"OTM Introduction",tag:"Module 2",desc:"User login, authentication, and dashboard overview.",content:`<h3>User Login and Authentication</h3><p>Access to OTM is provided through your assigned credentials. Carriers must use only their authorized accounts and avoid sharing passwords with unauthorized team members.</p><h3>Dashboard Overview</h3><ul><li>View active and upcoming shipment tenders</li><li>Monitor shipment status and progress</li><li>Access communication tools and notifications</li><li>Manage transport documents and POD</li><li>Check dock schedules and appointments</li></ul>`,quiz:[{q:"What should carriers avoid regarding their OTM login credentials?",options:["Using a strong password","Logging in daily","Sharing passwords with drivers or subcontractors","Updating their profile"],correct:2},{q:"Which of the following can be accessed from the OTM dashboard?",options:["Social media integration","Active shipment tenders and dock schedules","Weather forecasting tools","Tax filing services"],correct:1}]}, es:{title:"Introducción a OTM",tag:"Módulo 2",desc:"Inicio de sesión, autenticación y descripción general del panel de control.",content:`<h3>Inicio de sesión y autenticación</h3><p>El acceso a OTM se proporciona mediante las credenciales asignadas. Los transportistas deben usar únicamente sus cuentas autorizadas y evitar compartir contraseñas.</p><h3>Panel de control</h3><ul><li>Ver licitaciones de envío activas y próximas</li><li>Monitorear el estado y progreso de los envíos</li><li>Acceder a herramientas de comunicación y notificaciones</li><li>Gestionar documentos de transporte y POD</li><li>Verificar horarios y citas de muelles</li></ul>`,quiz:[{q:"¿Qué deben evitar los transportistas respecto a sus credenciales?",options:["Usar una contraseña segura","Iniciar sesión diariamente","Compartir contraseñas con conductores o subcontratistas","Actualizar su perfil"],correct:2},{q:"¿A qué se puede acceder desde el panel de control?",options:["Integración con redes sociales","Licitaciones activas y horarios de muelles","Herramientas de pronóstico del tiempo","Servicios de declaración de impuestos"],correct:1}]}, pt:{title:"Introdução ao OTM",tag:"Módulo 2",desc:"Login, autenticação e visão geral do painel de controle.",content:`<h3>Login e autenticação</h3><p>O acesso ao OTM é fornecido por meio de credenciais atribuídas. As transportadoras devem usar apenas suas contas autorizadas e evitar compartilhar senhas.</p><h3>Painel de controle</h3><ul><li>Ver ofertas de frete ativas e futuras</li><li>Monitorar o status das remessas</li><li>Acessar ferramentas de comunicação e notificações</li><li>Gerenciar documentos de transporte e POD</li><li>Verificar agendamentos de docas</li></ul>`,quiz:[{q:"O que as transportadoras devem evitar em relação às credenciais do OTM?",options:["Usar uma senha forte","Fazer login diariamente","Compartilhar senhas com motoristas ou subcontratados","Atualizar seu perfil"],correct:2},{q:"O que pode ser acessado pelo painel do OTM?",options:["Integração com redes sociais","Ofertas de frete ativas e agendamentos de docas","Ferramentas de previsão do tempo","Serviços de declaração de impostos"],correct:1}]} },
    { id:3, video:"https://wnypubltm64soaxh.public.blob.vercel-storage.com/module3.mp4", en:{title:"Shipment Tendering",tag:"Module 3",desc:"Understanding tenders, acceptance, rejection, spot bids, and negotiation.",content:`<h3>What is a Tender?</h3><p>A shipment tender is a formal request sent by the shipper to a carrier through OTM, offering the opportunity to transport goods. Key elements include shipment details, pickup and delivery information, transportation mode, cost and rates, and a tender deadline.</p><h3>Acceptance and Rejection</h3><p>When a carrier accepts a tender, they agree to pick up and deliver the shipment on time at the agreed rate. Carriers may reject for valid reasons:</p><ul><li>Capacity constraints: insufficient vehicles for the requested time windows</li><li>Rate disagreement: proposed rate does not meet expectations</li><li>Special handling: inability to manage specific requirements</li></ul><h3>Spot Bids and Negotiation</h3><p>When standard tenders are not accepted, OTM supports spot bidding and negotiation processes to reach mutually agreeable terms.</p>`,quiz:[{q:"What is a shipment tender in OTM?",options:["A delivery confirmation document","A formal request sent to a carrier to transport goods","A payment invoice for completed shipments","A dock scheduling tool"],correct:1},{q:"What does OTM support when standard tenders are not accepted?",options:["Automatic cancellation","Spot bidding and negotiation","Mandatory acceptance","Legal proceedings"],correct:1}]}, es:{title:"Licitación de Envíos",tag:"Módulo 3",desc:"Comprensión de licitaciones, aceptación, rechazo y negociación.",content:`<h3>¿Qué es una licitación?</h3><p>Una licitación de envío es una solicitud formal enviada por el cargador a un transportista a través de OTM. Los elementos clave incluyen detalles del envío, información de recogida y entrega, modal de transporte, tarifas y un plazo de respuesta.</p><h3>Aceptación y rechazo</h3><p>Al aceptar una licitación, el transportista se compromete a recoger y entregar el envío a tiempo y a la tarifa acordada. Los transportistas pueden rechazar por:</p><ul><li>Restricciones de capacidad</li><li>Desacuerdo en tarifas</li><li>Manejo especial requerido</li></ul><h3>Ofertas spot y negociación</h3><p>Cuando no se aceptan las licitaciones estándar, OTM admite procesos de negociación para llegar a términos mutuamente aceptables.</p>`,quiz:[{q:"¿Qué es una licitación de envío en OTM?",options:["Un documento de confirmación de entrega","Una solicitud formal enviada a un transportista para transportar mercancías","Una factura de pago","Una herramienta de programación de muelles"],correct:1},{q:"¿Qué admite OTM cuando no se aceptan las licitaciones estándar?",options:["Cancelación automática","Ofertas spot y negociación","Aceptación obligatoria","Procedimientos legales"],correct:1}]}, pt:{title:"Oferta de Frete",tag:"Módulo 3",desc:"Entendimento de ofertas, aceitação, rejeição e negociação.",content:`<h3>O que é uma oferta de frete?</h3><p>Uma oferta de frete é uma solicitação formal enviada pelo embarcador a uma transportadora pelo OTM. Os elementos principais incluem detalhes da remessa, informações de coleta e entrega, modal, tarifas e prazo de resposta.</p><h3>Aceitação e rejeição</h3><p>Ao aceitar uma oferta, a transportadora se compromete a coletar e entregar a remessa no prazo e pela tarifa acordada. As transportadoras podem rejeitar por:</p><ul><li>Restrições de capacidade</li><li>Desacordo sobre tarifas</li><li>Requisitos especiais de manuseio</li></ul><h3>Licitações spot e negociação</h3><p>Quando as ofertas padrão não são aceitas, o OTM suporta processos de negociação para chegar a termos mutuamente aceitáveis.</p>`,quiz:[{q:"O que é uma oferta de frete no OTM?",options:["Um documento de confirmação de entrega","Uma solicitação formal enviada a uma transportadora para transportar mercadorias","Uma fatura de pagamento","Uma ferramenta de agendamento de docas"],correct:1},{q:"O que o OTM suporta quando as ofertas padrão não são aceitas?",options:["Cancelamento automático","Licitações spot e negociação","Aceitação obrigatória","Procedimentos legais"],correct:1}]} },
    { id:4, video:"https://wnypubltm64soaxh.public.blob.vercel-storage.com/module4.mp4", en:{title:"Dock & Yard Management",tag:"Module 4",desc:"Dock booking, scheduling, capacity planning, and real-time visibility.",content:`<h3>Dock Booking and Scheduling</h3><p>Plans, coordinates, and manages the arrival and departure of trucks at a warehouse to ensure efficient loading and unloading without congestion.</p><ul><li>Appointment Management: carriers reserve time slots in advance</li><li>Dock Allocation: the system assigns the most suitable dock door based on shipment type, equipment needs, and warehouse capacity</li><li>Capacity Planning: ensures resources such as forklifts, staff, and dock space are balanced across the day</li><li>Real-Time Visibility: live updates on truck arrival status, delays, dock occupancy, and ongoing operations</li><li>Exception Handling: addresses late arrivals, urgent shipments, or overbooked time slots</li></ul>`,quiz:[{q:"What is the main purpose of Dock Booking and Scheduling?",options:["To track driver salaries","To ensure loading and unloading happen efficiently and without congestion","To manage carrier invoices","To store shipment documents"],correct:1},{q:"Which process assigns the most suitable dock door based on shipment type?",options:["Capacity planning","Dock allocation","Exception handling","POD upload"],correct:1}]}, es:{title:"Gestión de Muelles y Patio",tag:"Módulo 4",desc:"Reserva, programación, planificación de capacidad y visibilidad en tiempo real.",content:`<h3>Reserva y programación de muelles</h3><p>Planifica, coordina y gestiona la llegada y salida de camiones para garantizar actividades eficientes sin congestión.</p><ul><li>Gestión de citas: reserva de franjas horarias con anticipación</li><li>Asignación de muelle: el sistema asigna la puerta más adecuada según tipo de envío, necesidades de equipos y capacidad</li><li>Planificación de capacidad: recursos como montacargas, personal y espacio equilibrados durante el día</li><li>Visibilidad en tiempo real: actualizaciones en vivo sobre llegadas, retrasos y ocupación de muelles</li><li>Gestión de excepciones: llegadas tardías, envíos urgentes o sobrecontratación</li></ul>`,quiz:[{q:"¿Cuál es el propósito principal de la Reserva y Programación de Muelles?",options:["Rastrear salarios de conductores","Garantizar que las actividades de carga y descarga ocurran eficientemente sin congestión","Gestionar facturas de transportistas","Almacenar documentos de envío"],correct:1},{q:"¿Qué proceso asigna la puerta de muelle más adecuada según el tipo de envío?",options:["Planificación de capacidad","Asignación de muelle","Gestión de excepciones","Carga de POD"],correct:1}]}, pt:{title:"Gestão de Docas e Pátio",tag:"Módulo 4",desc:"Agendamento de docas, planejamento de capacidade e visibilidade em tempo real.",content:`<h3>Agendamento de docas</h3><p>Planeja, coordena e gerencia a chegada e saída de caminhões para garantir operações eficientes sem congestionamento.</p><ul><li>Gerenciamento de agendamentos: transportadoras reservam horários com antecedência</li><li>Alocação de doca: o sistema atribui a porta mais adequada com base no tipo de remessa, necessidades de equipamentos e capacidade</li><li>Planejamento de capacidade: recursos como empilhadeiras, equipe e espaço equilibrados ao longo do dia</li><li>Visibilidade em tempo real: atualizações ao vivo sobre chegadas, atrasos e ocupação de docas</li><li>Gestão de exceções: chegadas atrasadas, remessas urgentes ou excesso de reservas</li></ul>`,quiz:[{q:"Qual é o principal objetivo do agendamento de docas?",options:["Rastrear salários de motoristas","Garantir que o carregamento e descarregamento ocorram eficientemente sem congestionamento","Gerenciar faturas de transportadoras","Armazenar documentos de remessa"],correct:1},{q:"Qual processo atribui a porta de doca mais adequada com base no tipo de remessa?",options:["Planejamento de capacidade","Alocação de doca","Gestão de exceções","Upload de POD"],correct:1}]} },
    { id:5, video:"https://wnypubltm64soaxh.public.blob.vercel-storage.com/module5.mp4", en:{title:"Dock Changes & Rescheduling",tag:"Module 5",desc:"Managing adjustments to planned dock appointments.",content:`<h3>Dock Changes and Rescheduling</h3><p>Adjustments to planned dock appointments are required when real-world events deviate from the original plan. The process ensures loading and unloading activities remain synchronized with available resources by:</p><ul><li>Reassigning Dock Doors: allocating a different dock to accommodate changing capacity or equipment requirements</li><li>Modifying Appointment Times: shifting time slots when carriers face delays or priority shipments must be accelerated</li><li>Balancing Workload: ensuring staff, forklifts, and space are evenly utilized to prevent congestion or downtime</li><li>Maintaining Real-Time Coordination: keeping carriers and warehouse teams aligned with continuously updated information</li><li>Reducing Operational Disruptions: quickly adjusting the schedule to minimize waiting times and preserve productivity</li></ul>`,quiz:[{q:"When is Dock Rescheduling typically required?",options:["When all shipments arrive on time","When carriers share their credentials","When real-world events deviate from the original plan, such as delayed trucks","When invoices are submitted"],correct:2},{q:"What must carriers do when a dock appointment change occurs?",options:["Wait for the warehouse to notice","Notify the warehouse team promptly and update OTM in real time","Cancel the shipment","Request a new tender"],correct:1}]}, es:{title:"Cambios y Reprogramación de Muelles",tag:"Módulo 5",desc:"Gestión de ajustes a las citas de muelle planificadas.",content:`<h3>Cambios y reprogramación de muelles</h3><p>Los ajustes son necesarios cuando los eventos del mundo real se desvían del plan original. El proceso garantiza que las actividades de carga y descarga permanezcan sincronizadas mediante:</p><ul><li>Reasignación de muelles: asignar un muelle diferente para acomodar cambios de capacidad o equipos</li><li>Modificación de horarios: cambiar franjas cuando los transportistas enfrentan retrasos o los envíos urgentes deben acelerarse</li><li>Equilibrio de carga de trabajo: garantizar que el personal, montacargas y espacio estén distribuidos uniformemente</li><li>Coordinación en tiempo real: mantener a transportistas y equipos de almacén alineados con información actualizada</li><li>Reducción de interrupciones: ajustar rápidamente el horario para minimizar tiempos de espera</li></ul>`,quiz:[{q:"¿Cuándo se requiere típicamente la Reprogramación de Muelles?",options:["Cuando todos los envíos llegan a tiempo","Cuando los transportistas comparten sus credenciales","Cuando los eventos del mundo real se desvían del plan original, como camiones retrasados","Cuando se envían facturas"],correct:2},{q:"¿Qué deben hacer los transportistas cuando ocurre un cambio en la cita de muelle?",options:["Esperar a que el almacén lo note","Notificar al equipo del almacén con prontitud y actualizar OTM en tiempo real","Cancelar el envío","Solicitar una nueva licitación"],correct:1}]}, pt:{title:"Alterações e Reagendamento de Docas",tag:"Módulo 5",desc:"Gerenciamento de ajustes nos agendamentos de docas planejados.",content:`<h3>Alterações e reagendamento de docas</h3><p>Ajustes são necessários quando eventos reais desviam do plano original. O processo garante que as atividades de carregamento e descarregamento permaneçam sincronizadas por meio de:</p><ul><li>Reatribuição de docas: alocar uma doca diferente para acomodar mudanças de capacidade ou equipamentos</li><li>Modificação de horários: deslocar horários quando transportadoras enfrentam atrasos ou remessas prioritárias precisam ser aceleradas</li><li>Balanceamento da carga de trabalho: garantir que equipe, empilhadeiras e espaço estejam distribuídos uniformemente</li><li>Coordenação em tempo real: manter transportadoras e equipes do armazém alinhadas com informações atualizadas</li><li>Redução de interrupções: ajustar rapidamente o cronograma para minimizar tempos de espera</li></ul>`,quiz:[{q:"Quando o reagendamento de docas é tipicamente necessário?",options:["Quando todas as remessas chegam no prazo","Quando as transportadoras compartilham suas credenciais","Quando eventos reais desviam do plano original, como caminhões atrasados","Quando faturas são enviadas"],correct:2},{q:"O que as transportadoras devem fazer quando ocorre uma mudança no agendamento?",options:["Aguardar o armazém perceber","Notificar a equipe do armazém prontamente e atualizar o OTM em tempo real","Cancelar a remessa","Solicitar uma nova oferta"],correct:1}]} },
    { id:6, video:"https://wnypubltm64soaxh.public.blob.vercel-storage.com/module6.mp4", en:{title:"Shipment Execution",tag:"Module 6",desc:"Information updates, real-time tracking, and status updates.",content:`<h3>Information Updates</h3><p>Capturing and communicating all relevant shipment events throughout the transportation lifecycle, including statuses such as departure, arrival, delays, and carrier confirmations.</p><ul><li>Real-time status capture: pickup, in-transit events, customs clearance, delivery, and POD</li><li>Exception reporting: delays, route changes, damage reports, or failed delivery attempts</li><li>Compliance and documentation: updating digital documents such as transport documents and delivery notes to reflect the latest shipment events</li><li>Stakeholder communication: providing carriers, customers, warehouse teams, and planning units with timely updates</li></ul><h3>Tracking and Status Updates</h3><p>Monitoring shipment progress and communicating accurate, timely information as goods move from origin to destination.</p><ul><li>Movement Tracking: monitoring real-time location updates and transit milestones through GPS or carrier updates</li><li>Status Event Reporting: recording key events such as pickup, loading, customs release, departure, arrival, unloading, delivery, and POD confirmation</li><li>Exception Management: logging delays, route deviations, damages, or failed delivery attempts</li><li>Visibility for Stakeholders: providing transparent tracking information to carriers, planners, and customer service teams</li></ul>`,quiz:[{q:"Which of the following must a carrier report as an exception in OTM?",options:["A shipment delivered on time","A route change or failed delivery attempt","A new dock appointment confirmed in advance","A tender accepted within the deadline"],correct:1},{q:"Which statuses must be captured in real time during shipment execution?",options:["Only the final delivery status","Pickup, in-transit events, customs clearance, delivery, and POD","Only delays and damages","Only the departure status"],correct:1}]}, es:{title:"Ejecución de Envíos",tag:"Módulo 6",desc:"Actualizaciones de información, rastreo en tiempo real y actualizaciones de estado.",content:`<h3>Actualizaciones de información</h3><p>Captura y comunicación de todos los eventos relevantes durante el ciclo de vida del transporte, incluyendo salida, llegada, retrasos y confirmaciones.</p><ul><li>Captura de estado en tiempo real: recogida, eventos en tránsito, despacho de aduanas, entrega y POD</li><li>Reporte de excepciones: retrasos, cambios de ruta, informes de daños o intentos fallidos de entrega</li><li>Cumplimiento y documentación: actualización de documentos de transporte para reflejar los últimos eventos del envío</li><li>Comunicación con partes interesadas: actualizaciones oportunas a transportistas, clientes y equipos de almacén</li></ul><h3>Rastreo y actualizaciones de estado</h3><p>Monitoreo del progreso del envío y comunicación de información precisa y oportuna a medida que las mercancías se mueven de origen a destino.</p><ul><li>Rastreo de movimiento: actualizaciones de ubicación en tiempo real y hitos de tránsito mediante GPS o actualizaciones del transportista</li><li>Reporte de eventos de estado: registro de recogida, carga, despacho aduanero, salida, llegada, descarga, entrega y confirmación de POD</li><li>Gestión de excepciones: registro de retrasos, desviaciones de ruta, daños o intentos fallidos de entrega</li><li>Visibilidad para partes interesadas: información de rastreo transparente para transportistas, planificadores y equipos de atención al cliente</li></ul>`,quiz:[{q:"¿Cuál debe reportar un transportista como excepción en OTM?",options:["Un envío entregado a tiempo","Un cambio de ruta o intento fallido de entrega","Una nueva cita de muelle confirmada","Una licitación aceptada dentro del plazo"],correct:1},{q:"¿Qué estados deben capturarse en tiempo real durante la ejecución?",options:["Solo el estado de entrega final","Recogida, eventos en tránsito, despacho de aduanas, entrega y POD","Solo retrasos y daños","Solo el estado de salida"],correct:1}]}, pt:{title:"Execução de Remessas",tag:"Módulo 6",desc:"Atualizações de informações, rastreamento em tempo real e atualizações de status.",content:`<h3>Atualizações de informações</h3><p>Captura e comunicação de todos os eventos relevantes durante o ciclo de vida do transporte, incluindo saída, chegada, atrasos e confirmações.</p><ul><li>Captura de status em tempo real: coleta, eventos em trânsito, despacho aduaneiro, entrega e POD</li><li>Relatório de exceções: atrasos, mudanças de rota, relatórios de danos ou tentativas de entrega fracassadas</li><li>Conformidade e documentação: atualização de documentos de transporte para refletir os eventos mais recentes</li><li>Comunicação com partes interessadas: atualizações oportunas para transportadoras, clientes e equipes de armazém</li></ul><h3>Rastreamento e atualizações de status</h3><p>Monitoramento do progresso da remessa e comunicação de informações precisas e oportunas à medida que as mercadorias se movem da origem ao destino.</p><ul><li>Rastreamento de movimento: atualizações de localização em tempo real e marcos de trânsito via GPS ou atualizações da transportadora</li><li>Relatório de eventos de status: registro de coleta, carregamento, liberação aduaneira, saída, chegada, descarregamento, entrega e confirmação de POD</li><li>Gestão de exceções: registro de atrasos, desvios de rota, danos ou tentativas de entrega fracassadas</li><li>Visibilidade para partes interessadas: informações de rastreamento transparentes para transportadoras, planejadores e equipes de atendimento ao cliente</li></ul>`,quiz:[{q:"O que uma transportadora deve reportar como exceção no OTM?",options:["Uma remessa entregue no prazo","Uma mudança de rota ou tentativa de entrega fracassada","Um novo agendamento de doca confirmado","Uma oferta aceita dentro do prazo"],correct:1},{q:"Quais status devem ser capturados em tempo real durante a execução?",options:["Apenas o status de entrega final","Coleta, eventos em trânsito, despacho aduaneiro, entrega e POD","Apenas atrasos e danos","Apenas o status de saída"],correct:1}]} },
    { id:7, video:"https://wnypubltm64soaxh.public.blob.vercel-storage.com/module7.mp4", en:{title:"ATA Updates & Fault Codes",tag:"Module 7",desc:"Recording actual arrival times and capturing execution-related issues.",content:`<h3>ATA Updates</h3><p>ATA (Actual Time of Arrival) updates ensure accurate arrival times are recorded promptly, keeping planned and actual timelines aligned and supporting KPIs like transit performance and OTIF.</p><ul><li>ATA must be entered as soon as the truck arrives at the facility</li><li>Late or missing ATA entries affect dock planning and downstream operations</li><li>ATA data feeds into carrier performance metrics and KPI reporting</li><li>Ensures event validation and milestone updates for smooth downstream processes such as dock operations and inventory updates</li></ul><h3>Fault Codes</h3><p>Fault codes capture issues that arise during shipment execution, enabling structured identification of disruptions and supporting issue diagnosis.</p><ul><li>Delays caused by traffic, weather, or mechanical failure</li><li>Equipment failures such as refrigeration or loading issues</li><li>Missing or incorrect documentation</li><li>Missed scans or system transmission errors</li><li>Ensures timely escalation so planners and warehouse teams can respond proactively</li></ul>`,quiz:[{q:"What does ATA stand for in the context of OTM?",options:["Automated Tracking Alert","Actual Time of Arrival","Advanced Transport Assignment","Authorized Tender Acceptance"],correct:1},{q:"What is the purpose of fault codes in OTM?",options:["To rate carrier performance monthly","To identify and record disruptions such as delays, equipment failures, or missing documents","To generate invoices automatically","To plan new transportation routes"],correct:1}]}, es:{title:"Actualizaciones ATA y Códigos de Falla",tag:"Módulo 7",desc:"Registro de tiempos reales de llegada y captura de problemas de ejecución.",content:`<h3>Actualizaciones ATA</h3><p>Las actualizaciones ATA (Tiempo Real de Llegada) garantizan que los tiempos de llegada reales se registren con prontitud, manteniendo alineados los cronogramas planificados y reales, y apoyando KPIs como el rendimiento de tránsito y OTIF.</p><ul><li>El ATA debe ingresarse en cuanto el camión llega a las instalaciones</li><li>Las entradas tardías o faltantes afectan la planificación de muelles y operaciones posteriores</li><li>Los datos de ATA alimentan las métricas de rendimiento del transportista y los reportes de KPI</li><li>Garantiza la validación de eventos y actualizaciones de hitos para procesos posteriores fluidos</li></ul><h3>Códigos de Falla</h3><p>Los códigos de falla capturan los problemas que surgen durante la ejecución, habilitando la identificación estructurada de interrupciones.</p><ul><li>Retrasos por tráfico, clima o falla mecánica</li><li>Fallas de equipos como refrigeración o problemas de carga</li><li>Documentación faltante o incorrecta</li><li>Escaneos perdidos o errores de transmisión del sistema</li><li>Garantiza la escalada oportuna para que planificadores y equipos respondan proactivamente</li></ul>`,quiz:[{q:"¿Qué significa ATA en el contexto de OTM?",options:["Alerta de Rastreo Automatizado","Tiempo Real de Llegada","Asignación de Transporte Avanzado","Aceptación de Licitación Autorizada"],correct:1},{q:"¿Cuál es el propósito de los códigos de falla en OTM?",options:["Calificar el rendimiento mensualmente","Identificar y registrar interrupciones como retrasos, fallas de equipos o documentos faltantes","Generar facturas automáticamente","Planificar nuevas rutas"],correct:1}]}, pt:{title:"Atualizações de ATA e Códigos de Falha",tag:"Módulo 7",desc:"Registro de horários reais de chegada e captura de problemas de execução.",content:`<h3>Atualizações de ATA</h3><p>As atualizações de ATA (Horário Real de Chegada) garantem que os horários sejam registrados prontamente, mantendo os cronogramas planejados e reais alinhados e apoiando KPIs como desempenho de trânsito e OTIF.</p><ul><li>O ATA deve ser inserido assim que o caminhão chegar às instalações</li><li>Entradas tardias ou ausentes afetam o planejamento de docas e operações posteriores</li><li>Os dados de ATA alimentam as métricas de desempenho e relatórios de KPI</li><li>Garante a validação de eventos e atualizações de marcos para processos posteriores tranquilos</li></ul><h3>Códigos de Falha</h3><p>Os códigos de falha capturam problemas durante a execução, habilitando a identificação estruturada de interrupções.</p><ul><li>Atrasos por tráfego, clima ou falha mecânica</li><li>Falhas de equipamentos como refrigeração ou problemas de carregamento</li><li>Documentação faltante ou incorreta</li><li>Scans perdidos ou erros de transmissão do sistema</li><li>Garante a escalada oportuna para que planejadores e equipes respondam proativamente</li></ul>`,quiz:[{q:"O que significa ATA no contexto do OTM?",options:["Alerta de Rastreamento Automático","Horário Real de Chegada","Atribuição de Transporte Avançado","Aceitação de Oferta Autorizada"],correct:1},{q:"Qual é o propósito dos códigos de falha no OTM?",options:["Avaliar o desempenho mensal","Identificar e registrar interrupções como atrasos, falhas de equipamentos ou documentos faltantes","Gerar faturas automaticamente","Planejar novas rotas"],correct:1}]} },
    { id:8, video:"https://wnypubltm64soaxh.public.blob.vercel-storage.com/module10.mp4", en:{title:"Document Management",tag:"Module 8",desc:"Transport document and POD upload — ensuring proper documentation, compliance, and traceability.",content:`<h3>Document Upload</h3><p>Document Management focuses on capturing and uploading essential transportation documents to ensure proper documentation flow, compliance, and traceability across the supply chain. Accurate and timely uploads directly support invoicing, claims handling, delivery confirmation, and overall execution visibility.</p><ul><li>Transport Document: documents shipment details such as shipper, consignee, cargo description, and transport conditions — serving as both a receipt and a legal contract</li><li>Proof of Delivery (POD): confirms that goods have been successfully delivered to the consignee, including signatures, timestamps, and condition notes</li><li>Document accuracy: uploaded files must match the actual shipment and contain all required fields</li><li>Traceability: documents stored in accessible digital repositories support claims, disputes, and compliance audits</li><li>Faster response: timely POD upload allows quick proof of delivery to respond to customer demands efficiently and support financial settlements</li><li>Reduces manual errors: digitizing document handling replaces paper-based or email-based exchanges with structured system uploads</li></ul>`,quiz:[{q:"Which document confirms that goods have been successfully delivered, including signatures and timestamps?",options:["The shipment tender","The Proof of Delivery (POD)","The dock booking confirmation","The ATA update"],correct:1},{q:"What is the main reason for uploading the POD promptly in OTM?",options:["To trigger a new shipment tender","To provide quick proof of delivery and respond to customer demands efficiently","To generate ATA fault codes","To create new shipment tenders automatically"],correct:1}]}, es:{title:"Gestión de Documentos",tag:"Módulo 8",desc:"Carga de documento de transporte y POD — garantizando documentación adecuada, cumplimiento y trazabilidad.",content:`<h3>Carga de documentos</h3><p>La Gestión de Documentos se enfoca en capturar y cargar documentos de transporte esenciales para garantizar un flujo de documentación adecuado, cumplimiento y trazabilidad en toda la cadena de suministro.</p><ul><li>Documento de Transporte: documenta los detalles del envío como cargador, consignatario, descripción de la carga y condiciones de transporte — sirviendo como recibo y contrato legal</li><li>Prueba de entrega (POD): confirma que las mercancías fueron entregadas exitosamente al consignatario, incluyendo firmas, marcas de tiempo y notas de condición</li><li>Precisión de documentos: los archivos cargados deben coincidir con el envío real y contener todos los campos requeridos</li><li>Trazabilidad: los documentos digitales apoyan reclamaciones, disputas y auditorías de cumplimiento</li><li>Respuesta ágil: la carga oportuna del POD permite atender demandas del cliente eficientemente y apoya las liquidaciones financieras</li><li>Reduce errores manuales: la digitalización reemplaza los intercambios en papel o correo electrónico</li></ul>`,quiz:[{q:"¿Qué documento confirma que las mercancías fueron entregadas exitosamente, incluyendo firmas y marcas de tiempo?",options:["La licitación de envío","La Prueba de Entrega (POD)","La confirmación de reserva de muelle","La actualización ATA"],correct:1},{q:"¿Cuál es la razón principal para cargar el POD con prontitud?",options:["Para activar una nueva licitación","Para tener el comprobante de entrega de forma ágil y atender las demandas del cliente eficientemente","Para generar códigos de falla ATA","Para crear automáticamente nuevas licitaciones"],correct:1}]}, pt:{title:"Gestão de Documentos",tag:"Módulo 8",desc:"Upload de documento de transporte e POD — garantindo documentação adequada, conformidade e rastreabilidade.",content:`<h3>Upload de documentos</h3><p>A Gestão de Documentos foca na captura e upload de documentos de transporte essenciais para garantir fluxo adequado, conformidade e rastreabilidade em toda a cadeia de suprimentos.</p><ul><li>Documento de Transporte: documenta os detalhes da remessa como embarcador, destinatário, descrição da carga e condições de transporte — servindo como recibo e contrato legal</li><li>Comprovante de entrega (POD): confirma que as mercadorias foram entregues ao destinatário, incluindo assinaturas, carimbos de tempo e notas de condição</li><li>Precisão dos documentos: os arquivos devem corresponder à remessa real e conter todos os campos obrigatórios</li><li>Rastreabilidade: documentos digitais suportam reclamações, disputas e auditorias de conformidade</li><li>Resposta ágil: o upload oportuno do POD permite atender demandas do cliente eficientemente e suporta liquidações financeiras</li><li>Reduz erros manuais: a digitalização substitui trocas em papel ou e-mail</li></ul>`,quiz:[{q:"Qual documento confirma que as mercadorias foram entregues com sucesso, incluindo assinaturas e carimbos de tempo?",options:["A oferta de frete","O Comprovante de Entrega (POD)","A confirmação de agendamento de doca","A atualização de ATA"],correct:1},{q:"Qual é o principal motivo para fazer o upload do POD prontamente?",options:["Para acionar uma nova oferta de frete","Para ter comprovante de entrega de forma ágil e atender demandas do cliente eficientemente","Para gerar códigos de falha ATA","Para criar novas ofertas automaticamente"],correct:1}]} },
    { id:9, video:"https://wnypubltm64soaxh.public.blob.vercel-storage.com/module8.mp4", en:{title:"Communication Management",tag:"Module 9",desc:"OTM Chats and notifications for efficient, traceable collaboration.",content:`<h3>OTM Chats</h3><p>OTM Chats facilitates efficient and traceable communication directly within OTM, centralizing discussions around specific shipments, orders, or events.</p><ul><li>Real-time communication tied to specific shipments or execution events</li><li>Context-linked messaging: comment directly within a shipment or order record for clearer understanding</li><li>Traceable communication history: valuable for audits, dispute resolution, and future reference</li><li>Improves collaboration between planners, carriers, warehouses, and customer service</li><li>Reduces response times through notifications and message prompts within OTM</li><li>Reduces fragmentation across emails, calls, or external messaging tools</li></ul><h3>OTM Notifications</h3><p>Proactive, configurable alerts that keep execution partners aligned and responsive throughout the transport lifecycle.</p><ul><li>Event-based alerts: tender sent/accepted, pickup confirmed, in-transit updates, delivery, and POD captured</li><li>Exception notifications: delays, missed appointments, capacity shortfalls, route deviations, or document mismatches</li><li>Audience targeting: ensuring the right users receive relevant alerts without noise</li><li>Multi-channel delivery: in-app, email, or integrated webhooks</li><li>Configurable rules and thresholds matching business priorities and service levels</li></ul>`,quiz:[{q:"What is a key advantage of OTM Chats over external messaging tools?",options:["It is faster to type","It centralizes shipment-linked conversations and maintains a traceable communication history","It allows anonymous messaging","It replaces the need for shipment tenders"],correct:1},{q:"Which type of notification alerts carriers about delays or missed appointments?",options:["Event-based alerts","Exception notifications","Financial alerts","Login notifications"],correct:1}]}, es:{title:"Gestión de Comunicación",tag:"Módulo 9",desc:"Chats y notificaciones de OTM para una colaboración eficiente y trazable.",content:`<h3>Chats de OTM</h3><p>Los Chats de OTM facilitan la comunicación eficiente y trazable directamente dentro de OTM, centralizando las discusiones alrededor de envíos específicos.</p><ul><li>Comunicación en tiempo real vinculada a envíos o eventos de ejecución específicos</li><li>Mensajería vinculada al contexto: comentar directamente en un registro de envío para mayor claridad</li><li>Historial de comunicación trazable: valioso para auditorías, resolución de disputas y referencia futura</li><li>Mejora la colaboración entre planificadores, transportistas, almacenes y atención al cliente</li><li>Reduce los tiempos de respuesta mediante notificaciones y avisos dentro de OTM</li><li>Reduce la fragmentación entre correos, llamadas o herramientas de mensajería externa</li></ul><h3>Notificaciones de OTM</h3><p>Alertas configurables y proactivas que mantienen a los socios alineados durante el ciclo de vida del transporte.</p><ul><li>Alertas basadas en eventos: licitación enviada/aceptada, recogida confirmada, actualizaciones en tránsito, entrega y POD capturado</li><li>Notificaciones de excepciones: retrasos, citas perdidas, déficit de capacidad, desviaciones de ruta o discrepancias en documentos</li><li>Segmentación de audiencia: garantizando que los usuarios correctos reciban alertas relevantes</li><li>Entrega multicanal: en la aplicación, correo electrónico o webhooks integrados</li><li>Reglas y umbrales configurables que coinciden con las prioridades del negocio</li></ul>`,quiz:[{q:"¿Cuál es una ventaja clave de los Chats de OTM?",options:["Es más rápido escribir","Centraliza las conversaciones vinculadas a envíos y mantiene un historial trazable","Permite mensajes anónimos","Reemplaza la necesidad de licitaciones"],correct:1},{q:"¿Qué tipo de notificación alerta sobre retrasos o citas perdidas?",options:["Alertas basadas en eventos","Notificaciones de excepciones","Alertas financieras","Notificaciones de inicio de sesión"],correct:1}]}, pt:{title:"Gestão de Comunicação",tag:"Módulo 9",desc:"Chats e notificações do OTM para colaboração eficiente e rastreável.",content:`<h3>Chats do OTM</h3><p>Os Chats do OTM facilitam comunicação eficiente e rastreável diretamente no OTM, centralizando discussões em torno de remessas específicas.</p><ul><li>Comunicação em tempo real vinculada a remessas ou eventos de execução específicos</li><li>Mensagens vinculadas ao contexto: comentar diretamente em um registro de remessa para maior clareza</li><li>Histórico de comunicação rastreável: valioso para auditorias, resolução de disputas e referência futura</li><li>Melhora a colaboração entre planejadores, transportadoras, armazéns e atendimento ao cliente</li><li>Reduz os tempos de resposta por meio de notificações e avisos no OTM</li><li>Reduz fragmentação entre e-mails, chamadas ou ferramentas de mensagens externas</li></ul><h3>Notificações do OTM</h3><p>Alertas configuráveis e proativos que mantêm os parceiros alinhados durante o ciclo de vida do transporte.</p><ul><li>Alertas baseados em eventos: oferta enviada/aceita, coleta confirmada, atualizações em trânsito, entrega e POD capturado</li><li>Notificações de exceções: atrasos, agendamentos perdidos, déficit de capacidade, desvios de rota ou discrepâncias em documentos</li><li>Segmentação de audiência: garantindo que os usuários certos recebam alertas relevantes</li><li>Entrega multicanal: no app, e-mail ou webhooks integrados</li><li>Regras e limites configuráveis que correspondem às prioridades do negócio</li></ul>`,quiz:[{q:"Qual é a principal vantagem dos Chats do OTM?",options:["É mais rápido digitar","Centraliza conversas vinculadas a remessas e mantém histórico rastreável","Permite mensagens anônimas","Substitui a necessidade de ofertas de frete"],correct:1},{q:"Qual tipo de notificação alerta sobre atrasos ou agendamentos perdidos?",options:["Alertas baseados em eventos","Notificações de exceções","Alertas financeiros","Notificações de login"],correct:1}]} },
    { id:10, video:null, en:{title:"Compliance & Security",tag:"Module 10",desc:"Data protection best practices and secure usage of OTM.",content:`<h3>Protect Data</h3><p>Carriers must use OTM in a secure, compliant, and responsible way, protecting shipment data, documents, and communications shared through the platform.</p><ul><li>Use only authorized OTM credentials — do not share passwords with drivers, subcontractors, or unauthorized team members</li><li>Respect role-based visibility — access only shipments and data relevant to you; avoid attempting to access restricted information</li><li>Handle documents (transport documents, POD, invoices) accurately and completely</li><li>Use OTM Chats safely — avoid sharing personal data, financial details, or unnecessary metadata</li><li>Verify information before uploading to prevent data inconsistencies</li><li>Monitor OTM notifications securely without exposing shipment information outside approved channels</li><li>Log out after completing tasks, especially on shared or on-the-road devices</li><li>Report any system issues or suspicious activity immediately to your transportation analyst focal point</li><li>Follow document retention and deletion practices based on contractual and compliance requirements</li></ul>`,quiz:[{q:"What should carriers do after completing their tasks in OTM on shared devices?",options:["Leave the session open","Log out to prevent unauthorized access","Delete all shipment records","Transfer credentials to a colleague"],correct:1},{q:"What should a carrier do if they notice suspicious activity in OTM?",options:["Ignore it and continue working","Try to resolve it independently","Report it immediately to your transportation analyst focal point","Share the issue on external messaging platforms"],correct:2}]}, es:{title:"Cumplimiento y Seguridad",tag:"Módulo 10",desc:"Mejores prácticas de protección de datos y uso seguro de OTM.",content:`<h3>Proteger los datos</h3><p>Los transportistas deben usar OTM de manera segura, conforme y responsable, protegiendo los datos de envío, documentos y comunicaciones compartidas.</p><ul><li>Use solo las credenciales de OTM autorizadas — no comparta contraseñas con conductores, subcontratistas o miembros no autorizados</li><li>Respete la visibilidad basada en roles — acceda solo a los envíos y datos relevantes para usted</li><li>Maneje los documentos (documentos de transporte, POD, facturas) con precisión y completitud</li><li>Use los Chats de OTM de forma segura — evite compartir datos personales o detalles financieros</li><li>Verifique la información antes de cargarla para evitar inconsistencias de datos</li><li>Monitoree las notificaciones de OTM de forma segura sin exponer información fuera de canales aprobados</li><li>Cierre sesión después de completar sus tareas, especialmente en dispositivos compartidos o en ruta</li><li>Reporte cualquier actividad sospechosa a su analista de transporte focal point</li><li>Siga las prácticas de retención y eliminación de documentos</li></ul>`,quiz:[{q:"¿Qué deben hacer los transportistas después de completar sus tareas en dispositivos compartidos?",options:["Dejar la sesión abierta","Cerrar sesión para evitar accesos no autorizados","Eliminar todos los registros de envío","Transferir credenciales a un colega"],correct:1},{q:"¿Qué debe hacer un transportista si nota actividad sospechosa en OTM?",options:["Ignorarlo y continuar trabajando","Intentar resolverlo de forma independiente","Reportarlo de inmediato a su analista de transporte focal point","Compartir el problema en plataformas externas"],correct:2}]}, pt:{title:"Conformidade e Segurança",tag:"Módulo 10",desc:"Boas práticas de proteção de dados e uso seguro do OTM.",content:`<h3>Proteger os dados</h3><p>As transportadoras devem usar o OTM de forma segura, em conformidade e responsável, protegendo dados de remessa, documentos e comunicações compartilhadas.</p><ul><li>Use apenas credenciais autorizadas — não compartilhe senhas com motoristas, subcontratados ou membros não autorizados</li><li>Respeite a visibilidade baseada em função — acesse apenas remessas e dados relevantes para você</li><li>Gerencie documentos (documentos de transporte, POD, faturas) com precisão e completude</li><li>Use os Chats do OTM com segurança — evite compartilhar dados pessoais ou detalhes financeiros</li><li>Verifique as informações antes de fazer upload para evitar inconsistências de dados</li><li>Monitore as notificações do OTM com segurança sem expor informações fora de canais aprovados</li><li>Faça logout após concluir tarefas, especialmente em dispositivos compartilhados ou em campo</li><li>Reporte qualquer atividade suspeita ao seu analista de transporte focal point</li><li>Siga as práticas de retenção e exclusão de documentos</li></ul>`,quiz:[{q:"O que as transportadoras devem fazer após concluir tarefas em dispositivos compartilhados?",options:["Deixar a sessão aberta","Fazer logout para evitar acesso não autorizado","Excluir todos os registros de remessa","Transferir credenciais para um colega"],correct:1},{q:"O que uma transportadora deve fazer se notar atividade suspeita?",options:["Ignorar e continuar trabalhando","Tentar resolver de forma independente","Reportar imediatamente ao seu analista de transporte focal point","Compartilhar o problema em plataformas externas"],correct:2}]} },
  ],
  'fault-codes': [
    { id:1, video:null, en:{title:"Fault Codes Overview",tag:"Module 1",desc:"Coming soon — content will be added shortly.",content:`<h3>Coming Soon</h3><p>This module is under development. Content will be added shortly.</p>`,quiz:[{q:"Placeholder question 1",options:["Option A","Option B","Option C","Option D"],correct:0},{q:"Placeholder question 2",options:["Option A","Option B","Option C","Option D"],correct:0}]}, es:{title:"Resumen de Códigos de Falla",tag:"Módulo 1",desc:"Próximamente.",content:`<h3>Próximamente</h3><p>Este módulo está en desarrollo.</p>`,quiz:[{q:"Pregunta de marcador 1",options:["Opción A","Opción B","Opción C","Opción D"],correct:0},{q:"Pregunta de marcador 2",options:["Opción A","Opción B","Opción C","Opción D"],correct:0}]}, pt:{title:"Visão Geral dos Códigos de Falha",tag:"Módulo 1",desc:"Em breve.",content:`<h3>Em breve</h3><p>Este módulo está em desenvolvimento.</p>`,quiz:[{q:"Pergunta 1",options:["Opção A","Opção B","Opção C","Opção D"],correct:0},{q:"Pergunta 2",options:["Opção A","Opção B","Opção C","Opção D"],correct:0}]} }
  ],
  'freight-settlement': [
    { id:1, video:null, en:{title:"Freight Settlement Overview",tag:"Module 1",desc:"Coming soon — content will be added shortly.",content:`<h3>Coming Soon</h3><p>This module is under development. Content will be added shortly.</p>`,quiz:[{q:"Placeholder question 1",options:["Option A","Option B","Option C","Option D"],correct:0},{q:"Placeholder question 2",options:["Option A","Option B","Option C","Option D"],correct:0}]}, es:{title:"Resumen de Liquidación de Flete",tag:"Módulo 1",desc:"Próximamente.",content:`<h3>Próximamente</h3><p>Este módulo está en desarrollo.</p>`,quiz:[{q:"Pregunta de marcador 1",options:["Opción A","Opción B","Opción C","Opción D"],correct:0},{q:"Pregunta de marcador 2",options:["Opción A","Opción B","Opción C","Opción D"],correct:0}]}, pt:{title:"Visão Geral da Liquidação de Frete",tag:"Módulo 1",desc:"Em breve.",content:`<h3>Em breve</h3><p>Este módulo está em desenvolvimento.</p>`,quiz:[{q:"Pergunta 1",options:["Opção A","Opção B","Opção C","Opção D"],correct:0},{q:"Pergunta 2",options:["Opção A","Opção B","Opção C","Opção D"],correct:0}]} }
  ]
}

const labels = {
  en:{modules:'Modules',finalQuiz:'Final Quiz',prev:'← Previous',next:'Next →',goQuiz:'Go to Final Quiz →',quizTitle:'Final Knowledge Check',quizDesc:'Answer all questions. You need 90% or more to pass.',submit:'Submit Quiz',restart:'Restart',pass:'Congratulations! You passed.',fail:'You did not reach the minimum score of 90%.',review:'Modules to review:',logout:'Logout',selectSection:'Select a training section to begin',glossary:'Glossary',backToSections:'← Back to sections'},
  es:{modules:'Módulos',finalQuiz:'Quiz Final',prev:'← Anterior',next:'Siguiente →',goQuiz:'Ir al Quiz Final →',quizTitle:'Verificación Final',quizDesc:'Responde todas las preguntas. Necesitas 90% o más para aprobar.',submit:'Enviar Quiz',restart:'Reiniciar',pass:'¡Felicitaciones! Aprobaste.',fail:'No alcanzaste la puntuación mínima del 90%.',review:'Módulos para revisar:',logout:'Cerrar sesión',selectSection:'Selecciona una sección de capacitación para comenzar',glossary:'Glosario',backToSections:'← Volver a secciones'},
  pt:{modules:'Módulos',finalQuiz:'Quiz Final',prev:'← Anterior',next:'Próximo →',goQuiz:'Ir para o Quiz Final →',quizTitle:'Verificação Final',quizDesc:'Responda todas as perguntas. Você precisa de 90% ou mais para passar.',submit:'Enviar Quiz',restart:'Reiniciar',pass:'Parabéns! Você passou.',fail:'Você não atingiu a pontuação mínima de 90%.',review:'Módulos para revisar:',logout:'Sair',selectSection:'Selecione uma seção de treinamento para começar',glossary:'Glossário',backToSections:'← Voltar às seções'}
}

export default function TrainingPage() {
  const [lang, setLang] = useState(null)
  const [activeSection, setActiveSection] = useState(null)
  const [currentModule, setCurrentModule] = useState(0)
  const [showQuiz, setShowQuiz] = useState(false)
  const [showGlossary, setShowGlossary] = useState(false)
  const [quizAnswers, setQuizAnswers] = useState({})
  const [quizSubmitted, setQuizSubmitted] = useState(false)
  const [quizResult, setQuizResult] = useState(null)
  const [userName, setUserName] = useState('')
  const router = useRouter()

  useEffect(() => {
    const token = localStorage.getItem('token')
    if (!token) { router.push('/login'); return }
    if (localStorage.getItem('role') === 'admin') { router.push('/admin'); return }
    setUserName(localStorage.getItem('name') || '')
  }, [])

  function logout() { localStorage.clear(); router.push('/login') }
  const tx = labels[lang] || labels.en
  const sectionModules = activeSection ? modules[activeSection] : []
  const progress = sectionModules.length ? Math.round(((currentModule + 1) / sectionModules.length) * 100) : 0

  async function submitQuiz() {
    let correct = 0; let total = 0; const failedMods = []
    sectionModules.forEach((m, mi) => {
      const d = m[lang]
      let modCorrect = 0
      d.quiz.forEach((q, qi) => {
        total++
        const ans = quizAnswers[`${mi}-${qi}`]
        if (ans === q.correct) { correct++; modCorrect++ }
      })
      if (modCorrect < d.quiz.length) failedMods.push(m[lang].tag + ': ' + m[lang].title)
    })
    const score = Math.round((correct / total) * 100)
    const passed = score >= PASS_SCORE
    setQuizSubmitted(true)
    setQuizResult({ score, passed, failedMods })
    const token = localStorage.getItem('token')
    await fetch('/api/quiz/submit', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
      body: JSON.stringify({ score, passed, answers: quizAnswers, language: lang, section: activeSection })
    })
  }

  function selectSection(slug) {
    setActiveSection(slug); setCurrentModule(0); setShowQuiz(false)
    setShowGlossary(false); setQuizAnswers({}); setQuizSubmitted(false); setQuizResult(null)
  }

  if (!lang) return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-[#003865] via-[#005B9A] to-[#0078C8]">
      <div className="bg-white rounded-2xl shadow-2xl p-10 text-center max-w-md w-full">
        <div className="inline-block bg-[#003865] text-white text-xs font-bold tracking-widest px-4 py-2 rounded mb-6">OTM CARRIERS TRAINING</div>
        <h1 className="text-2xl font-bold text-[#003865] mb-2">Welcome{userName ? `, ${userName}` : ''}</h1>
        <p className="text-gray-400 text-sm mb-8">Choose your language / Elija su idioma / Escolha seu idioma</p>
        <div className="flex gap-4 justify-center">
          {[['en','🇺🇸','English'],['es','🇪🇸','Español'],['pt','🇧🇷','Português']].map(([code,flag,label]) => (
            <button key={code} onClick={() => setLang(code)}
              className="flex-1 flex flex-col items-center gap-2 border-2 border-gray-200 rounded-xl py-4 hover:border-[#003865] hover:bg-[#E8F3FB] transition font-semibold text-[#003865]">
              <span className="text-3xl">{flag}</span><span className="text-sm">{label}</span>
            </button>
          ))}
        </div>
      </div>
    </div>
  )

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-[#003865] text-white px-6 h-16 flex items-center justify-between sticky top-0 z-50 shadow-lg">
        <div><div className="font-bold">OTM Carriers Training</div><div className="text-xs opacity-60">{userName}</div></div>
        <div className="flex items-center gap-3">
          <select value={lang} onChange={e => setLang(e.target.value)} className="bg-white/10 border border-white/20 text-white text-xs rounded-full px-3 py-1 focus:outline-none">
            <option value="en">🇺🇸 EN</option><option value="es">🇪🇸 ES</option><option value="pt">🇧🇷 PT</option>
          </select>
          <button onClick={logout} className="text-xs bg-white/10 hover:bg-white/20 px-4 py-1.5 rounded-full transition">{tx.logout}</button>
        </div>
      </header>

      {activeSection && <div className="bg-[#005B9A] h-1"><div className="h-full bg-[#5BC8F5] transition-all duration-500" style={{width: (showQuiz||showGlossary) ? '100%' : progress+'%'}}></div></div>}

      {!activeSection ? (
        <div className="max-w-3xl mx-auto px-6 py-16">
          <h2 className="text-3xl font-bold text-[#003865] mb-2" style={{fontFamily:'Georgia,serif'}}>Training Sections</h2>
          <p className="text-gray-400 mb-10">{tx.selectSection}</p>
          <div className="grid gap-4">
            {sections.map(s => (
              <button key={s.slug} onClick={() => selectSection(s.slug)}
                className="bg-white rounded-2xl shadow-sm p-6 text-left hover:shadow-md hover:border-[#0078C8] border-2 border-transparent transition group">
                <div className="flex items-center justify-between">
                  <div>
                    <div className="text-xs font-bold uppercase tracking-widest text-[#0078C8] mb-1">{s.slug.replace('-',' ').toUpperCase()}</div>
                    <div className="text-lg font-bold text-[#003865]">{s[lang]}</div>
                    <div className="text-sm text-gray-400 mt-1">{modules[s.slug]?.length || 0} {tx.modules.toLowerCase()}</div>
                  </div>
                  <div className="text-2xl text-gray-200 group-hover:text-[#0078C8] transition">→</div>
                </div>
              </button>
            ))}
          </div>
        </div>
      ) : (
        <div className="flex" style={{minHeight:'calc(100vh - 68px)'}}>
          <aside className="w-64 bg-white border-r border-gray-100 py-4 sticky top-16 h-[calc(100vh-68px)] overflow-y-auto hidden md:block flex-shrink-0">
            <button onClick={() => setActiveSection(null)} className="flex items-center gap-2 px-5 py-2 text-xs text-gray-400 hover:text-[#003865] transition mb-2">{tx.backToSections}</button>
            <div className="text-xs font-bold uppercase tracking-widest text-gray-400 px-5 mb-2">{tx.modules}</div>
            {sectionModules.map((m,i) => (
              <div key={m.id} onClick={() => { setShowQuiz(false); setShowGlossary(false); setCurrentModule(i) }}
                className={`flex items-center gap-3 px-5 py-2.5 cursor-pointer border-l-[3px] text-sm font-medium transition ${!showQuiz && !showGlossary && i===currentModule ? 'bg-[#E8F3FB] border-[#0078C8] text-[#003865] font-semibold' : 'border-transparent text-gray-500 hover:bg-gray-50'}`}>
                <span className="text-xs text-gray-400 w-4">{m.id}</span>
                <div className="w-2 h-2 rounded-full bg-gray-200 flex-shrink-0"></div>
                <span className="truncate">{m[lang].title}</span>
              </div>
            ))}
            {activeSection === 'basic' && (
              <div onClick={() => { setShowGlossary(true); setShowQuiz(false) }}
                className={`flex items-center gap-3 px-5 py-2.5 cursor-pointer border-l-[3px] text-sm font-medium transition mt-1 ${showGlossary ? 'bg-[#E8F3FB] border-[#0078C8] text-[#003865] font-semibold' : 'border-transparent text-gray-500 hover:bg-gray-50'}`}>
                <span className="text-xs text-gray-400 w-4">📖</span>
                <div className="w-2 h-2 rounded-full bg-gray-200 flex-shrink-0"></div>
                <span>{tx.glossary}</span>
              </div>
            )}
            <div onClick={() => { setShowQuiz(true); setShowGlossary(false) }}
              className={`flex items-center gap-3 px-5 py-2.5 cursor-pointer border-l-[3px] text-sm font-medium transition mt-1 border-t border-gray-100 ${showQuiz ? 'bg-[#E8F3FB] border-[#0078C8] text-[#003865] font-semibold' : 'border-transparent text-gray-500 hover:bg-gray-50'}`}>
              <span className="text-xs text-gray-400 w-4">★</span>
              <div className="w-2 h-2 rounded-full bg-gray-200 flex-shrink-0"></div>
              <span>{tx.finalQuiz}</span>
            </div>
          </aside>

          <main className="flex-1 p-8 max-w-3xl">
            {showGlossary ? (
              <GlossaryView lang={lang} tx={tx} glossary={glossary} />
            ) : !showQuiz ? (
              <ModuleView m={sectionModules[currentModule]} lang={lang} tx={tx}
                isLast={currentModule===sectionModules.length-1}
                onPrev={() => setCurrentModule(i => i-1)}
                onNext={() => setCurrentModule(i => i+1)}
                onQuiz={() => setShowQuiz(true)}
                showPrev={currentModule > 0} />
            ) : (
              <QuizView modules={sectionModules} lang={lang} tx={tx}
                answers={quizAnswers} setAnswers={setQuizAnswers}
                submitted={quizSubmitted} result={quizResult} onSubmit={submitQuiz}
                onRestart={() => { setShowQuiz(false); setCurrentModule(0); setQuizAnswers({}); setQuizSubmitted(false); setQuizResult(null) }} />
            )}
          </main>
        </div>
      )}
    </div>
  )
}

function GlossaryView({ lang, tx, glossary }) {
  const terms = glossary[lang] || glossary.en
  return (
    <div>
      <div className="mb-6">
        <span className="inline-block text-xs font-bold uppercase tracking-widest text-[#0078C8] bg-[#E8F3FB] px-3 py-1 rounded mb-3">📖 {tx.glossary}</span>
        <h2 className="text-3xl font-bold text-[#003865] mb-2" style={{fontFamily:'Georgia,serif'}}>{tx.glossary}</h2>
        <p className="text-gray-500 text-sm">{terms.length} terms</p>
      </div>
      <div className="space-y-3">
        {terms.map((item, i) => (
          <div key={i} className="bg-white rounded-xl shadow-sm p-5">
            <div className="font-bold text-[#003865] mb-1">{item.term}</div>
            <div className="text-gray-500 text-sm leading-relaxed">{item.def}</div>
          </div>
        ))}
      </div>
    </div>
  )
}

function ModuleView({ m, lang, tx, isLast, onPrev, onNext, onQuiz, showPrev }) {
  const d = m[lang]
  return (
    <div>
      <div className="mb-6">
        <span className="inline-block text-xs font-bold uppercase tracking-widest text-[#0078C8] bg-[#E8F3FB] px-3 py-1 rounded mb-3">{d.tag}</span>
        <h2 className="text-3xl font-bold text-[#003865] mb-2" style={{fontFamily:'Georgia,serif'}}>{d.title}</h2>
        <p className="text-gray-500 text-sm">{d.desc}</p>
      </div>
      {m.video && (
        <div className="bg-[#003865] rounded-xl overflow-hidden mb-5 shadow-lg">
          <video controls controlsList="nodownload" onContextMenu={e => e.preventDefault()} className="w-full" style={{aspectRatio:'16/9'}} src={m.video}
            onError={e => { e.target.style.display='none'; e.target.parentElement.innerHTML+='<div style="aspect-ratio:16/9;display:flex;align-items:center;justify-content:center;background:linear-gradient(135deg,#002244,#003865);color:rgba(255,255,255,0.3);font-size:0.85rem">Video not found</div>' }} />
          <div className="px-4 py-2 text-xs text-white/40 border-t border-white/10">{d.tag} — {d.title}</div>
        </div>
      )}
      <div className="bg-white rounded-xl shadow-sm p-6 mb-5"
        dangerouslySetInnerHTML={{__html: d.content
          .replace(/<h3>/g,'<h3 style="color:#003865;font-weight:700;font-size:1rem;margin-top:16px;margin-bottom:8px">')
          .replace(/<ul>/g,'<ul style="list-style:disc;padding-left:20px;margin:8px 0">')
          .replace(/<li>/g,'<li style="color:#4A5568;font-size:0.9rem;margin-bottom:4px;line-height:1.6">')
          .replace(/<p>/g,'<p style="color:#4A5568;font-size:0.92rem;line-height:1.7;margin-bottom:12px">')}} />
      <div className="flex gap-3 mt-6 pt-5 border-t border-gray-100">
        {showPrev && <button onClick={onPrev} className="border border-gray-200 text-gray-600 hover:border-[#0078C8] hover:text-[#0078C8] font-semibold px-5 py-2.5 rounded-lg text-sm transition">{tx.prev}</button>}
        {isLast
          ? <button onClick={onQuiz} className="ml-auto bg-[#003865] hover:bg-[#0078C8] text-white font-semibold px-5 py-2.5 rounded-lg text-sm transition">{tx.goQuiz}</button>
          : <button onClick={onNext} className="ml-auto bg-[#003865] hover:bg-[#0078C8] text-white font-semibold px-5 py-2.5 rounded-lg text-sm transition">{tx.next}</button>}
      </div>
    </div>
  )
}

function QuizView({ modules, lang, tx, answers, setAnswers, submitted, result, onSubmit, onRestart }) {
  return (
    <div>
      <div className="mb-6">
        <span className="inline-block text-xs font-bold uppercase tracking-widest text-[#0078C8] bg-[#E8F3FB] px-3 py-1 rounded mb-3">★ {tx.finalQuiz}</span>
        <h2 className="text-3xl font-bold text-[#003865] mb-2" style={{fontFamily:'Georgia,serif'}}>{tx.quizTitle}</h2>
        <p className="text-gray-500 text-sm">{tx.quizDesc}</p>
      </div>
      {modules.map((m, mi) => {
        const d = m[lang]
        return (
          <div key={m.id} className="bg-white rounded-xl shadow-sm p-6 mb-4">
            <div className="text-xs font-bold uppercase tracking-widest text-[#0078C8] mb-4">{d.tag} — {d.title}</div>
            {d.quiz.map((q, qi) => {
              const key = `${mi}-${qi}`
              const userAns = answers[key]
              return (
                <div key={qi} className="mb-5 last:mb-0">
                  <div className="font-semibold text-sm text-[#003865] mb-3"><span className="text-[#0078C8]">Q{mi*2+qi+1}.</span> {q.q}</div>
                  <div className="space-y-2">
                    {q.options.map((opt, oi) => {
                      let cls = 'border-gray-200 text-gray-600 hover:border-[#0078C8] hover:bg-[#E8F3FB]'
                      if (submitted) {
                        if (oi === q.correct) cls = 'border-green-400 bg-green-50 text-green-700 font-semibold'
                        else if (oi === userAns) cls = 'border-red-400 bg-red-50 text-red-600'
                        else cls = 'border-gray-100 text-gray-400'
                      } else if (userAns === oi) cls = 'border-[#0078C8] bg-[#E8F3FB] text-[#003865] font-medium'
                      return (
                        <label key={oi} className={`flex items-start gap-3 border-2 rounded-lg px-4 py-3 text-sm cursor-pointer transition ${cls}`}>
                          <input type="radio" name={key} value={oi} disabled={submitted}
                            checked={userAns === oi} onChange={() => setAnswers(a => ({...a, [key]: oi}))}
                            className="mt-0.5 flex-shrink-0 accent-[#0078C8]" />
                          {opt}
                        </label>
                      )
                    })}
                  </div>
                </div>
              )
            })}
          </div>
        )
      })}
      {!submitted && <button onClick={onSubmit} className="bg-[#003865] hover:bg-[#0078C8] text-white font-semibold px-8 py-3 rounded-lg transition mb-8">{tx.submit}</button>}
      {result && (
        <div className="bg-white rounded-2xl shadow-lg p-8 text-center mt-4 mb-8">
          <div className="text-4xl mb-3">{result.passed ? '🎉' : '📋'}</div>
          <div className={`text-5xl font-bold mb-3 ${result.passed ? 'text-green-600' : 'text-red-500'}`}>{result.score}%</div>
          <p className="text-gray-600 mb-4">{result.passed ? tx.pass : tx.fail}</p>
          {!result.passed && result.failedMods.length > 0 && (
            <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 mb-5 text-left">
              <div className="text-xs font-bold uppercase tracking-wide text-amber-700 mb-2">{tx.review}</div>
              <ul className="space-y-1">{result.failedMods.map((m,i) => <li key={i} className="text-sm text-amber-700">→ {m}</li>)}</ul>
            </div>
          )}
          <button onClick={onRestart} className="bg-[#003865] hover:bg-[#0078C8] text-white font-semibold px-6 py-2.5 rounded-lg transition">{tx.restart}</button>
        </div>
      )}
    </div>
  )
}
